
public class operator {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		
		int a=80;
		int b=46;
		System.out.println("the entered no is equal "+(a==b));
		System.out.println("the entered is not equal "+(a!=b));		
		System.out.println("the entered no is less than equal "+(a<b));
		System.out.println("the entered no is greater than equal "+(a>b));
		System.out.println("the entered no is less than or equal to "+(a<=b));
		System.out.println("the entered no has remider of "+(a%=b));
		
	}

	

	

}
